import{_ as a,o as r,c as o,a2 as e}from"./chunks/framework.Cr-Z7ngm.js";const c=JSON.parse('{"title":"动态","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/feed.md","filePath":"zh-CN/market-data/feed.md"}'),n={name:"market-data/feed.md"};function l(s,t,i,d,p,h){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="动态" tabindex="-1">动态 <a class="header-anchor" href="#动态" aria-label="Permalink to &quot;动态&quot;">​</a></h1><p>动态是 App 内的内容资讯中心，入口在底部导航「动态」Tab。提供社区内容、财经新闻、深度研报、业绩直播和投资教育等多种内容类型。</p><p>顶部频道 Tab：<strong>推荐 / 要闻 / 深度 / 直播 / 学堂 / 关注</strong></p><hr><h2 id="推荐" tabindex="-1">推荐 <a class="header-anchor" href="#推荐" aria-label="Permalink to &quot;推荐&quot;">​</a></h2><p>算法推荐的混合内容流，综合了社区帖子、新闻快讯和热点话题。推荐算法基于自选标的、关注账户、浏览历史和互动行为，持续使用后精准度会提升；可在帖子右上角选择「不感兴趣」来调整推荐。</p><p><strong>热点话题</strong>：顶部展示当前市场热门议题，点击进入专题讨论页。</p><p><strong>市场情绪指示器</strong>：显示港股温度、估值水位、市场情绪（如「港股 56.0° | 估值 极高 | 情绪 低」），点击查看详细分析。</p><p><strong>内容 Feed</strong>：社区帖子与资讯卡片混合展示，帖子支持点赞、评论、转发；点击 <code>$TICKER</code> 股票标签可直接跳转对应标的详情页。</p><hr><h2 id="要闻" tabindex="-1">要闻 <a class="header-anchor" href="#要闻" aria-label="Permalink to &quot;要闻&quot;">​</a></h2><p>财经新闻快讯，7×24 实时更新，按时间倒序排列。</p><p><strong>内容来源</strong>：华尔街见闻、智通财经、经济通等主流财经媒体，以及市场重要人物官方发言。</p><p><strong>置顶快讯</strong>：重要程度较高的新闻置顶显示，标有发布时间戳。</p><p><strong>股票关联标签</strong>：新闻下方附涉及的股票代码及当前涨跌幅，点击可跳转。</p><p>顶部可按「头条 / 加密货币」等分类筛选。点击新闻卡片进入详情页，右上角有分享按钮，支持复制链接或分享至社交平台。</p><hr><h2 id="深度" tabindex="-1">深度 <a class="header-anchor" href="#深度" aria-label="Permalink to &quot;深度&quot;">​</a></h2><p>专业研究报告和深度分析内容，主要来自海豚研究等机构。大部分内容免费；部分高端机构研报或专属课程可能需要特定行情权益或付费订阅。深度 Tab 内分两个子 Tab：<strong>深度</strong> 和 <strong>股票追踪</strong>。</p><h3 id="深度-1" tabindex="-1">深度 <a class="header-anchor" href="#深度-1" aria-label="Permalink to &quot;深度&quot;">​</a></h3><p><strong>内容类型</strong>：</p><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td>财报纪要</td><td>上市公司业绩电话会会议纪要</td></tr><tr><td>深度研报</td><td>行业分析、公司估值报告</td></tr><tr><td>今日重点消息</td><td>每日市场复盘摘要</td></tr></tbody></table><p><strong>检索</strong>：页面内搜索框可按公司名或代码找到对应深度报告。</p><p><strong>标签分类</strong>：估值、公告、驱动因子、财报等，方便分类浏览。</p><h3 id="股票追踪" tabindex="-1">股票追踪 <a class="header-anchor" href="#股票追踪" aria-label="Permalink to &quot;股票追踪&quot;">​</a></h3><p>按标的聚合分析观点，帮助用户追踪特定股票的市场看法变化。</p><ul><li>顶部搜索框：按公司名或股票代码检索</li><li>股票卡片：显示市场（如 US / HK）、公司名称、近 1 年观点数量</li><li>最新内容摘要：该标的最新一条相关资讯或分析文章标题</li></ul><p>点击卡片进入该标的的全部观点聚合页，查看对应公司的历史分析内容。</p><hr><h2 id="直播" tabindex="-1">直播 <a class="header-anchor" href="#直播" aria-label="Permalink to &quot;直播&quot;">​</a></h2><p>业绩电话会录像回放 + 平台公开课直播。</p><p><strong>内容类型</strong>：</p><ul><li><strong>业绩会议</strong>：上市公司季度/年度业绩电话会（中英文字幕）</li><li><strong>公开课</strong>：平台或合作机构组织的投资教育直播</li><li><strong>热点解读</strong>：围绕市场热点的专题直播</li><li><strong>新股追踪</strong>：IPO 路演及发行相关直播</li></ul><p><strong>使用方式</strong>：点击「预约」按钮对即将开始的直播设置提醒；已结束的直播点击后可观看回放（显示时长）。回放一般长期保留，但版权受限内容可能下架，建议感兴趣的内容及时观看。</p><hr><h2 id="学堂" tabindex="-1">学堂 <a class="header-anchor" href="#学堂" aria-label="Permalink to &quot;学堂&quot;">​</a></h2><p>投资教育课程库，按主题分类，适合系统学习。</p><p><strong>课程分类</strong>：</p><ul><li>美股入门（美股投资从 0 到 1）</li><li>期权期货</li><li>结构化产品</li><li>财务选股课</li><li>打新干货合集</li><li>基金</li></ul><p><strong>使用方式</strong>：点击课程卡片进入课时列表，支持订阅课程。订阅后在「最近在学」中快速续学，并显示订阅日期。</p><hr><h2 id="关注" tabindex="-1">关注 <a class="header-anchor" href="#关注" aria-label="Permalink to &quot;关注&quot;">​</a></h2><p>仅显示你关注的用户发布的内容。</p><p><strong>内容元素</strong>：用户昵称、认证标签、发布时间（含「已编辑」标记）、正文（支持股票标签和图表嵌入）、互动数据（赞/评论/观点数）。</p><p><strong>关注动态</strong>：也会显示你关注的用户的最新关注行为（如「1 小时前 · 关注了 XX」）。</p>',45)])])}const u=a(n,[["render",l]]);export{c as __pageData,u as default};
